def flip_bits_to_alternate(bit_string: str) -> str:
    n = len(bit_string)
    if n == 0:
        return ""

    flips_start_0 = 0
    flips_start_1 = 0

    for i in range(n):
        # Pattern starting with '0': 010101...
        # Expected char is '0' if i is even, '1' if i is odd.
        expected_char_0 = str(i % 2)
        if bit_string[i] != expected_char_0:
            flips_start_0 += 1

        # Pattern starting with '1': 101010...
        # Expected char is '1' if i is even, '0' if i is odd.
        expected_char_1 = str(1 - (i % 2))
        if bit_string[i] != expected_char_1:
            flips_start_1 += 1

    if flips_start_0 <= flips_start_1:
        # Construct the pattern "0101..."
        result_pattern = []
        for i in range(n):
            result_pattern.append(str(i % 2))
        return "".join(result_pattern)
    else:
        # Construct the pattern "1010..."
        result_pattern = []
        for i in range(n):
            result_pattern.append(str(1 - (i % 2)))
        return "".join(result_pattern)
